var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"NAYUBIN_ADMIN_NULL_NULL","text":{"KOREA":"저기군요.","JPN":"あそこですね。","ENG":"There it is.","TWN":"就在那裡呢。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L4_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"저게 당신이 말한 그 방주야? 상당히 낡았는데?","JPN":"あれがあなたの言っていた箱舟？　結構ボロいのね？","ENG":"So that's the Ark you were talking about? But it looks ancient!","TWN":"那就是你說的方舟？看起來很破舊啊？"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"부전대장님. 식별코드 확인됐습니다.","JPN":"副戦隊長殿。識別コードの確認ができました。","ENG":"Deputy Commander. We've confirmed the identification code.","TWN":"副隊長，已確認識別代碼。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":null,"C":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"순양함 코핀–6. 퇴역 전투함을 개조해서 만든 수송선입니다.","JPN":"巡洋艦コフィン-6。退役戦闘艦を改造した輸送船です。","ENG":"Cruiser Coffin-6. It's a retired warship modified into a cargo ship.","TWN":"是由退役戰艦《巡洋艦科芬-6》改造的運輸船。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":null,"C":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"이주는 고사하고 전투에도 쓰기 힘들어 보이는군.","JPN":"移住どころか戦闘に使うことすら厳しそうに見えるな。","ENG":"It looks hardly capable of combat, let alone transporting us to an entirely new world.","TWN":"別說遷移了，這東西看起來連要戰鬥都沒辦法。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"나유빈, 정말 제대로 찾아온 건가?","JPN":"イチノセ、本当にここで合っているのか？","ENG":"Are you sure this is the right ship, Yubin?","TWN":"羅瑜斌，你真的沒來錯地方嗎？"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"NAYUBIN_ADMIN_NULL_NULL","text":{"KOREA":"겉모습은 중요하지 않아요. 분명 시공간 종료를 견딜 수 있는 장비가 있을 겁니다.","JPN":"肝心なのは見た目じゃありません。きっと時空間終了に\\n耐えられる装備があるはずです。","ENG":"Looks can be deceiving. I'm certain it has some kind of equipment that will shelter us from the spacetime abortion.","TWN":"外觀並不重要，它一定安裝了能夠承受時空終止的設備。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"NAYUBIN_ADMIN_NULL_NULL","text":{"KOREA":"생존자들을 옮겨 태우려면 시간이 필요합니다. 그동안 함선의 시스템을 확인해 주세요.","JPN":"生存者たちの移乗には時間がかかります。\\nその間、艦船のシステムを確認してください。","ENG":"We need more time to board all the survivors. Please check the ship's systems in the meantime.","TWN":"把倖存者轉移到船上需要點時間。在這之前，請先確認艦船的系統。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":null,"text":{"KOREA":"중상자만 들것으로 옮겨! 걸을 수 있는 사람은 어서 탑승해!","JPN":"担架は重症者にのみ使え！　歩ける者はとっとと乗り込め！","ENG":"Carry only the gravely wounded on the stretchers! Everyone else, walk onboard!","TWN":"重傷患用擔架移動！能自己走的快點上船！"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":null,"text":{"KOREA":"남은 물자도 전부 실어야 한다! 굶어 죽기 싫으면 얼른 움직여!","JPN":"残りの物資も全部運び込むんだ！\\n飢え死にしたくなければテキパキ動け！","ENG":"We have to load up all the remaining supplies too! Get moving if you don't want to starve to death!","TWN":"剩餘物資也要全部搬上船！不想餓死就快點行動！"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"함교, 재기동은 순조롭나?","JPN":"艦橋、再起動は順調に進んでいるか？","ENG":"Bridge, how's the reactivation coming along?","TWN":"艦橋，重啟得順利嗎？"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SWORD_ADMIN_NULL_NULL","text":{"KOREA":"항법 장치가 너무 구식이라 애를 먹고 있습니다.","JPN":"航法装置があまりにも旧式なため、苦労しています。","ENG":"Not so smoothly. The navigation system is so outdated.","TWN":"導航裝置的型式太老舊了，非常棘手。"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"SWORD_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"SWORD_ADMIN_NULL_NULL","text":{"KOREA":"동력기관도 마찬가지라, 지금으로선 구조를 파악하는 것부터가 어려운 상황입니다.","JPN":"動力機関も同様でして、現状では\\n構造を把握することすら困難な状況です。","ENG":"Same with the engine. We're having enough trouble trying to figure out the architecture.","TWN":"動力機關也是。依目前的狀況，要掌握結構也很困難。"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"SWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"낭패로군......","JPN":"まずいな……","ENG":"This can't be good...","TWN":"這可麻煩了……"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"SWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L26_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"알겠다. 특이 사항이 있으면 즉각 보고하도록.","JPN":"わかった。異変があった場合は即刻報告するように。","ENG":"Very well. Report anything special to me right away.","TWN":"我知道了，如果發現特殊情況，立即向我報告。"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"SWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"예상보다 시간이 더 걸리겠어. 괜찮겠나.","JPN":"すまないが、予想よりも時間がかかりそうだ。","ENG":"This will take longer than we thought. Is that going to be okay?","TWN":"時間花得比預想的還要多，沒問題吧。"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};